section.code:
{
  "__faion_header__": {
    "methodology": "tree-testing",
    "version": "1.1.0",
    "produces": "config"
  },
  "tree": {
    "nodes": [
      "home",
      "shop",
      "shop/men",
      "shop/women",
      "shop/sale",
      "account",
      "support"
    ],
    "depth": 2
  },
  "tasks": [
    {
      "id": "t1",
      "prompt": "Where would you go to find sale items?",
      "expected_target": "shop/sale",
      "priority": "critical"
    },
    {
      "id": "t2",
      "prompt": "Where would you go to track your order?",
      "expected_target": "account",
      "priority": "high"
    },
    {
      "id": "t3",
      "prompt": "Where would you go for returns?",
      "expected_target": "support",
      "priority": "high"
    }
  ],
  "sample_plan": {
    "n_per_arm": 50,
    "arms": [
      "A",
      "B"
    ]
  },
  "metrics": [
    "success_rate",
    "directness",
    "first_click",
    "time"
  ]
}
